// === Parse JSON Entrada ===
// Recebe o texto colado no campo "Dados JSON" do formulario e extrai os campos.
const first = $input.first().json || {};
const raw = first["Dados JSON"] || first.dadosJson || first.data || first.json || "";

function cleanAndParse(input) {
  if (input == null) return {};
  if (typeof input === 'object') return input;
  let s = String(input).trim();
  // remove cercas markdown ```json ... ```
  s = s.replace(/```json/gi, '').replace(/```/g, '').trim();
  // localiza o primeiro { ou [
  const firstObj = s.indexOf('{');
  const firstArr = s.indexOf('[');
  let start = -1;
  if (firstArr !== -1 && (firstArr < firstObj || firstObj === -1)) {
    start = firstArr;
  } else {
    start = firstObj;
  }
  if (start > 0) s = s.slice(start);
  // localiza o ultimo } ou ]
  const lastObj = s.lastIndexOf('}');
  const lastArr = s.lastIndexOf(']');
  const end = Math.max(lastObj, lastArr);
  if (end !== -1) s = s.slice(0, end + 1);
  try {
    return JSON.parse(s);
  } catch (e) {
    // tenta remover virgulas pendentes
    try {
      return JSON.parse(s.replace(/,\s*([}\]])/g, '$1'));
    } catch (e2) {
      throw new Error('Nao foi possivel parsear o JSON de entrada: ' + e2.message);
    }
  }
}

let parsed = cleanAndParse(raw);
if (Array.isArray(parsed)) parsed = parsed[0] || {};

const jtbd = parsed.jtbd || {};
const pesquisa = parsed.pesquisa || {};
const estrategia = parsed.estrategia || {};

let numClips = parseInt(parsed.numClips, 10);
if (isNaN(numClips) || numClips < 14) numClips = 14;

let duracao = parseInt(parsed.duracaoClip, 10);
if (isNaN(duracao) || duracao <= 0) duracao = 4;

const servico = parsed.servico || parsed.keyword || 'Servico DJE';
const metaDesc = parsed.observacoes || (estrategia && estrategia.puv) || '';

return [{
  json: {
    articleTitle: servico,
    servico: servico,
    keyword: parsed.keyword || '',
    plataforma: parsed.plataforma || 'Facebook Ads',
    metaDescription: metaDesc,
    observacoes: parsed.observacoes || '',
    numberOfClips: numClips,
    duration: duracao,
    persona: parsed.persona || '',
    empresa: parsed.empresa || 'DJE Construcao e Reformas',
    jtbd: jtbd,
    pesquisa: pesquisa,
    estrategia: estrategia
  }
}];

// === Parser Roteiro ===
// Extrai o roteiro do Agente Diretor cobrindo TODAS as formas de saida do node OpenAI,
// inclusive a Responses API nova (output[0].content[0].text com o JSON dentro).
const item = $input.first().json || {};

function extractJson(s) {
  s = String(s).replace(/```json/gi, '').replace(/```/g, '').trim();
  const fo = s.indexOf('{');
  const fa = s.indexOf('[');
  let start = -1;
  if (fa !== -1 && (fa < fo || fo === -1)) start = fa; else start = fo;
  if (start > 0) s = s.slice(start);
  const lo = s.lastIndexOf('}');
  const la = s.lastIndexOf(']');
  const end = Math.max(lo, la);
  if (end !== -1) s = s.slice(0, end + 1);
  try { return JSON.parse(s); }
  catch (e) {
    try { return JSON.parse(s.replace(/,\s*([}\]])/g, '$1')); }
    catch (e2) { return null; }
  }
}

function looksLikeRoteiro(arr) {
  if (!Array.isArray(arr) || arr.length === 0) return false;
  const c = arr[0];
  if (!c || typeof c !== 'object') return false;
  return ('imagem_prompt' in c) || ('image_prompt' in c) || ('imagemPrompt' in c) ||
         ('prompt' in c) || ('texto_narracao' in c) || ('narracao' in c) ||
         ('narration' in c) || ('fase' in c);
}

function findRoteiro(obj) {
  if (!obj || typeof obj !== 'object') return null;
  if (Array.isArray(obj)) return looksLikeRoteiro(obj) ? obj : null;
  if (Array.isArray(obj.roteiro_video) && obj.roteiro_video.length) return obj.roteiro_video;
  for (const k of Object.keys(obj)) {
    if (Array.isArray(obj[k]) && looksLikeRoteiro(obj[k])) return obj[k];
  }
  return null;
}

function deepFind(node, depth) {
  if (node == null || depth > 8) return null;
  if (typeof node === 'string') {
    const parsed = extractJson(node);
    if (parsed) {
      const r = findRoteiro(parsed);
      if (r) return r;
      return deepFind(parsed, depth + 1);
    }
    return null;
  }
  if (typeof node === 'object') {
    const r = findRoteiro(node);
    if (r) return r;
    const vals = Array.isArray(node) ? node : Object.keys(node).map(function (k) { return node[k]; });
    for (const v of vals) {
      const d = deepFind(v, depth + 1);
      if (d) return d;
    }
  }
  return null;
}

let roteiro = deepFind(item, 0);

if (!roteiro) {
  const keys = Object.keys(item || {});
  let sample = '';
  try { sample = JSON.stringify(item); } catch (e) { sample = String(item); }
  if (sample && sample.length > 600) sample = sample.slice(0, 600);
  throw new Error('Parser Roteiro: nao encontrei roteiro_video. Keys: ' + JSON.stringify(keys) + '. Amostra: ' + sample);
}

const ctx = $('Edit Fields1').first().json || {};
roteiro = roteiro.map(function (c, i) {
  return {
    clip: c.clip || (i + 1),
    fase: c.fase || '',
    imagem_prompt: c.imagem_prompt || c.image_prompt || c.imagemPrompt || c.prompt || '',
    texto_narracao: c.texto_narracao || c.narracao || c.narration || '',
    articleTitle: ctx.articleTitle || '',
    duration: ctx.duration || 4
  };
});

return [{ json: { roteiro_video: roteiro } }];

// === PCM para WAV (Run Once for Each Item) ===
// Converte o audio base64 do Gemini TTS (PCM linear 16-bit mono 24000 Hz) em um WAV valido,
// prependendo um cabecalho WAV de 44 bytes (RIFF/WAVE/fmt /data).
const resp = $input.item.json || {};

function findInline(obj, depth) {
  if (obj == null || depth > 8) return null;
  if (typeof obj === 'object') {
    if (obj.inlineData && obj.inlineData.data) return obj.inlineData.data;
    if (obj.inline_data && obj.inline_data.data) return obj.inline_data.data;
    const vals = Array.isArray(obj) ? obj : Object.keys(obj).map(function (k) { return obj[k]; });
    for (const v of vals) {
      const r = findInline(v, depth + 1);
      if (r) return r;
    }
  }
  return null;
}

let b64 = '';
try { b64 = resp.candidates[0].content.parts[0].inlineData.data; } catch (e) { b64 = ''; }
if (!b64) { try { b64 = resp.candidates[0].content.parts[0].inline_data.data; } catch (e) { b64 = ''; } }
if (!b64) b64 = findInline(resp, 0) || '';
if (!b64) {
  throw new Error('PCM para WAV: nao encontrei o audio base64 em candidates[0].content.parts[0].inlineData.data');
}

const pcm = Buffer.from(b64, 'base64');
const numChannels = 1;
const sampleRate = 24000;
const bitsPerSample = 16;
const byteRate = sampleRate * numChannels * bitsPerSample / 8;
const blockAlign = numChannels * bitsPerSample / 8;
const dataSize = pcm.length;

const header = Buffer.alloc(44);
header.write('RIFF', 0, 'ascii');
header.writeUInt32LE(36 + dataSize, 4);
header.write('WAVE', 8, 'ascii');
header.write('fmt ', 12, 'ascii');
header.writeUInt32LE(16, 16);
header.writeUInt16LE(1, 20);
header.writeUInt16LE(numChannels, 22);
header.writeUInt32LE(sampleRate, 24);
header.writeUInt32LE(byteRate, 28);
header.writeUInt16LE(blockAlign, 32);
header.writeUInt16LE(bitsPerSample, 34);
header.write('data', 36, 'ascii');
header.writeUInt32LE(dataSize, 40);

const wavBuffer = Buffer.concat([header, pcm]);

return {
  json: Object.assign({}, resp, { audioFormat: 'wav', sampleRate: sampleRate, audioBytes: wavBuffer.length }),
  binary: { data: await this.helpers.prepareBinaryData(wavBuffer, 'audio.wav', 'audio/wav') }
};

// === Parse Generated Prompts ===
// Gera taskUUID (UUIDv4) e final_prompt por clip; define resolucao vertical 1080x1920.
// GUARDA: bloqueia clips com imagem_prompt vazio (evita positivePrompt vazio na RunWare).
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}
const items = $input.all();
const out = [];
for (let idx = 0; idx < items.length; idx++) {
  const it = items[idx];
  const j = it.json || {};
  const clipNum = j.clip || (idx + 1);
  const final_prompt = (j.imagem_prompt || j.final_prompt || '').toString().trim();
  if (final_prompt.length < 2) {
    throw new Error('Parse Generated Prompts: imagem_prompt vazio no clip ' + clipNum + '. Keys recebidas: ' + JSON.stringify(Object.keys(j)));
  }
  out.push({
    json: {
      ...j,
      final_prompt: final_prompt,
      taskUUID: uuidv4(),
      width: 1536,
      height: 2752,
      texto_narracao: j.texto_narracao || '',
      clip: j.clip
    }
  });
}
return out;

// === Agregar Tarefas ===
// Coleta TODOS os taskUUID gerados (1 por clip) em UM unico item de controle.
// Isso permite fazer o polling de TODAS as imagens de uma vez, sem perder itens
// no padrao IF+Wait (que descartava clips prontos em rodadas diferentes).
const src = $('Parse Generated Prompts').all();
const tasks = [];
for (let i = 0; i < src.length; i++) {
  const j = src[i].json || {};
  tasks.push({
    clip: Number(j.clip != null ? j.clip : (i + 1)),
    taskUUID: j.taskUUID,
    texto_narracao: j.texto_narracao || '',
    articleTitle: j.articleTitle || '',
    duration: Number(j.duration || 4)
  });
}
return [{ json: { tasks: tasks, total: tasks.length } }];

// === Processar Polling ===
// Le a resposta em LOTE do RunWare (getResponse de TODOS os taskUUID) e separa
// quais imagens ja ficaram prontas (tem imageURL) e quais ainda estao pendentes.
// Reconsulta TODOS os taskUUID a cada rodada (getResponse e idempotente: o RunWare
// guarda o resultado), entao nao precisamos acumular estado entre as voltas do loop.
const resp = $input.first().json || {};
let data = [];
if (Array.isArray(resp.data)) data = resp.data;
else if (resp.body && Array.isArray(resp.body.data)) data = resp.body.data;
else if (Array.isArray(resp)) data = resp;

const urlByUUID = {};
for (let i = 0; i < data.length; i++) {
  const d = data[i] || {};
  if (!d.taskUUID) continue;
  let url = d.imageURL || d.imageUrl || '';
  if (!url && Array.isArray(d.images) && d.images[0]) {
    url = d.images[0].imageURL || d.images[0].imageUrl || '';
  }
  if (url) urlByUUID[d.taskUUID] = url;
}

const tasks = ($('Agregar Tarefas').first().json.tasks) || [];
const ready = [];
const pending = [];
for (let i = 0; i < tasks.length; i++) {
  const t = tasks[i];
  const url = urlByUUID[t.taskUUID];
  if (url) ready.push(Object.assign({}, t, { imageURL: url }));
  else pending.push(t);
}

return [{
  json: {
    ready: ready,
    pending: pending,
    readyCount: ready.length,
    pendingCount: pending.length,
    poll_round: ($runIndex || 0)
  }
}];

// === Distribuir Imagens ===
// Converte o item de controle (com o array "ready") de volta em N itens,
// um por clip pronto, em ordem crescente de clip. Cada item leva a imageURL
// para o download e os metadados para o pareamento por clip no Merge.
const j = $input.first().json || {};
const ready = (j.ready || []).slice();
ready.sort(function (a, b) { return (Number(a.clip) || 0) - (Number(b.clip) || 0); });
if (ready.length === 0) {
  throw new Error('Distribuir Imagens: nenhuma imagem ficou pronta no RunWare apos o polling.');
}
return ready.map(function (t) {
  return {
    json: {
      clip: Number(t.clip),
      imageURL: t.imageURL,
      texto_narracao: t.texto_narracao || '',
      articleTitle: t.articleTitle || '',
      duration: Number(t.duration || 4)
    }
  };
});

// === Baixar Foto (Run Once for Each Item) ===
// Baixa a imagem gerada (URL publica do RunWare) para o binario "foto",
// preservando o json (clip, texto, etc.) para o pareamento por clip no Merge.
// Async via wrapper Promise manual sobre child_process.exec (nao bloqueia o event loop).
// Sem modulos bloqueados e sem sequencias de escape em strings (paste-safe).
const fs = require('fs');
const { exec } = require('child_process');
function execAsync(cmd, opts) {
  return new Promise(function (resolve, reject) {
    exec(cmd, opts, function (err, stdout, stderr) {
      if (err) { reject(err); } else { resolve({ stdout: stdout, stderr: stderr }); }
    });
  });
}
const TMP = '/tmp';
const UA = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36';
const j = $input.item.json || {};
const clipNum = Number(j.clip) || (($itemIndex || 0) + 1);
const url = String(j.imageURL || '').trim();
if (!url) {
  return { json: Object.assign({}, j, { clip: clipNum, skipped: true }) };
}
const imgPath = TMP + '/foto_' + clipNum + '.webp';
await execAsync('wget -q --user-agent="' + UA + '" -O "' + imgPath + '" "' + url + '"', { timeout: 120000, maxBuffer: 1024 * 1024 * 64 });
const buf = fs.readFileSync(imgPath);
return {
  json: Object.assign({}, j, { clip: clipNum }),
  binary: { foto: await this.helpers.prepareBinaryData(buf, 'foto_' + clipNum + '.webp', 'image/webp') }
};

// === Marcar Audio (Run Once for Each Item) ===
// O node de TTS (responseFormat=file) zera o json, deixando so o binario "data".
// Aqui reanexamos o numero do clip (e metadados) usando o item pareado de "item lists",
// para permitir o pareamento audio<->imagem por CLIP (e nao por posicao fragil).
const src = $('item lists').item.json || {};
return {
  json: {
    clip: Number(src.clip),
    texto_narracao: src.texto_narracao || '',
    articleTitle: src.articleTitle || '',
    duration: Number(src.duration || 4)
  },
  binary: $input.item.binary
};

// === Concatenar Audio (Run Once for All Items) ===
// Em ordem de clip, le os WAV (binary data) vindos do Merge, escreve em /tmp,
// concatena tudo num unico MP3 (ffmpeg), calcula a duracao de cada clipe (ffprobe)
// e os offsets cumulativos (start). Retorna scenes[] + binary data (narracao.mp3).
// Async via wrapper Promise manual sobre child_process.exec (sem util, sem helpers).
const fs = require('fs');
const path = require('path');
const { exec } = require('child_process');
function execAsync(cmd, opts) {
  return new Promise(function (resolve, reject) {
    exec(cmd, opts, function (err, stdout, stderr) {
      if (err) { reject(err); } else { resolve({ stdout: stdout, stderr: stderr }); }
    });
  });
}
const TMP = '/tmp';
function resolverCaminho(bin) {
  if (!bin) return null;
  const id = bin.id ? String(bin.id).split(':').pop() : null;
  const candidatos = [];
  if (id) {
    candidatos.push(
      path.join('/home/node/.n8n/binaryData', id),
      path.join('/home/node/.n8n/binaryData', id + '.bin'),
      path.join('/data/.n8n/binaryData', id),
      path.join('/tmp', id)
    );
  }
  for (const c of candidatos) { try { if (fs.existsSync(c)) return c; } catch (e) {} }
  return null;
}
async function getBuf(idx, prop, bin) {
  try {
    const b = await this.helpers.getBinaryDataBuffer(idx, prop);
    if (b && b.length) return b;
  } catch (e) {}
  const p = resolverCaminho(bin && bin[prop]);
  if (p) { try { return fs.readFileSync(p); } catch (e) {} }
  return null;
}
const items = $input.all();
const articleTitle = ($input.first().json && $input.first().json.articleTitle) || 'DJE';
const clips = [];
for (let i = 0; i < items.length; i++) {
  const j = items[i].json || {};
  const bin = items[i].binary || {};
  const clipNum = Number(j.clip) || (i + 1);
  const buf = await getBuf.call(this, i, 'data', bin);
  if (!buf || !buf.length) continue;
  clips.push({
    clip: clipNum,
    text: j.texto_narracao || '',
    imageUrl: j.imageURL || j.imageUrl || ''
    , buf: buf
  });
}
if (clips.length === 0) {
  throw new Error('Concatenar Audio: nenhum audio WAV recebido do Merge.');
}
clips.sort(function (a, b) { return (a.clip || 0) - (b.clip || 0); });
const wavPaths = [];
for (let k = 0; k < clips.length; k++) {
  const wp = TMP + '/hf_audio_' + clips[k].clip + '.wav';
  fs.writeFileSync(wp, clips[k].buf);
  wavPaths.push(wp);
}
const durations = [];
for (let k = 0; k < wavPaths.length; k++) {
  let dur = 0;
  try {
    const probe = await execAsync('ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "' + wavPaths[k] + '"', { timeout: 60000 });
    const d = parseFloat(String(probe.stdout).trim());
    if (!isNaN(d) && d > 0) dur = d;
  } catch (e) {}
  if (!dur) dur = 4;
  durations.push(dur);
}
const mp3Path = TMP + '/narracao_hf.mp3';
let inputs = '';
let filt = '';
for (let k = 0; k < wavPaths.length; k++) {
  inputs += ' -i "' + wavPaths[k] + '"';
  filt += '[' + k + ':a]';
}
filt += 'concat=n=' + wavPaths.length + ':v=0:a=1[out]';
await execAsync('ffmpeg -y' + inputs + ' -filter_complex "' + filt + '" -map "[out]" -c:a libmp3lame -b:a 192k "' + mp3Path + '"', { timeout: 240000, maxBuffer: 1024 * 1024 * 64 });
const scenes = [];
let acc = 0;
for (let k = 0; k < clips.length; k++) {
  const d = durations[k];
  scenes.push({
    index: clips[k].clip,
    imageUrl: clips[k].imageUrl,
    text: clips[k].text,
    start: Math.round(acc * 1000) / 1000,
    duration: Math.round(d * 1000) / 1000
  });
  acc += d;
}
const total = Math.round(acc * 1000) / 1000;
const mp3Buf = fs.readFileSync(mp3Path);
return [{
  json: { scenes: scenes, total: total, articleTitle: articleTitle },
  binary: { data: await this.helpers.prepareBinaryData(mp3Buf, 'narracao.mp3', 'audio/mpeg') }
}];

// === Montar Variables (Run Once for All Items) ===
// Monta o objeto variables (audioUrl + cta + scenes) e o corpo do render da
// HyperFrames. A URL publica do audio e derivada do Pull Zone do Bunny.
const cfg = $('Config').first().json || {};
const ca = $('Concatenar Audio').first().json || {};
const scenes = ca.scenes || [];
const articleTitle = ca.articleTitle || 'DJE';
const pullHost = String(cfg.bunnyPullHost || '').replace(/^https?:\/\//, '').replace(/\/$/, '');
const audioFileName = cfg.audioFileName || 'narracao.mp3';
const audioUrl = 'https://' + pullHost + '/audios/' + audioFileName;
const variables = {
  audioUrl: audioUrl,
  cta: { headline: 'Orçamento grátis', phone: '(11) 5891.6837' },
  scenes: scenes
};
const renderBody = {
  project: { type: 'url', url: cfg.hyperframesZipUrl },
  fps: 30,
  quality: 'standard',
  format: 'mp4',
  resolution: '1080p',
  aspect_ratio: '9:16',
  composition: 'index.html',
  variables: variables,
  title: articleTitle
};
return [{ json: { variables: variables, renderBody: renderBody, audioUrl: audioUrl, articleTitle: articleTitle } }];
